// Function to transform the data
function transformApiResponse(response) {
  const results = response.results;
  const output = [];

  results.forEach(result => {

    //  const timestamp = new Date(result.timestampUnix * 1000).toISOString();

    const istTimestamp = new Date(result.timestampUnix * 1000).toLocaleString('en-US', {
      timeZone: 'Asia/Kolkata'
    });

    const timestamp = new Date(new Date(istTimestamp).toISOString());

    if (result.results != null) {
      result.results.forEach(metric => {
      const { name, unit, baselineValue, comparatorValue } = metric;

      if (!baselineValue || !comparatorValue || baselineValue[0]?.value === 0 || comparatorValue[0]?.value === 0) return;

      const existingMetric = output.find(m => m.metric === name);

      const dataPoint = {
        baselineValue: baselineValue[0]?.value || null,
        comparatorValue: comparatorValue[0]?.value || null,
        timestamp: timestamp
      };

      if (existingMetric) {
        existingMetric.data.push(dataPoint);
      } else {
        output.push({
          metric: name,
          unit: unit,
          data: [dataPoint]
        });
      }
    });
    }
  });

  return output;
}

// Transform the response


const transformedData = transformApiResponse(data);

